INSERT INTO "public"."classes" ("id", "airtable_record_id", "class_id", "class_name", "description", "type", "age_range", "duration", "max_participants", "location", "instructor", "price", "booking_method", "registration_instructions", "is_active", "partner_organization", "city", "parking_instructions", "parking_map_url", "pricing_unit", "created_at", "updated_at") VALUES
	('26291989-a0c2-4547-b54c-18d7acbffac2', 'recEhlhOQktKr0ZOt', 'Mothers&Daughters City of WC', 'Mothers & Daughters ', NULL, 'Public: Mother & Daughter', '12-15', 3, 10, 'Civic Park Assembly Hall, 1375 Civic Dr., Walnut Creek, CA', 'Jay Beecham', 139, 'External', NULL, true, 'City of Walnut Creek -- Arts & Recreation', 'Walnut Creek', 'The entrance to the parking lot at Civic Park is off the east side of Civic Drive, just across from the Contra Costa County Fire Department. If you follow the red arrow **(SEE MAP BELOW)**  around the back of the Civic Park Community Center, you can park right next to the building where the class is being held.
 
Keep in mind that during most of the year, it will be getting dark or will be dark by the time class is over, so parking closer might be helpful. There is a short sidewalk from the parking lot to the Auditorium in the building on the right.', '/parking-map.png', 'Per Mother/Daughter Pair', '2025-07-25 23:51:27+00', '2026-04-22 04:40:57.20177+00'),
	('539e241d-baa3-4300-8b70-719bce31d3b9', 'recJlz1bcP7isy1rv', 'Mothers&Daughters - NCL', 'NCL Walnut Creek Class of ''27 - Women''s Self Defense & Personal Safety', NULL, 'Community: Mother & Daughter', '15+', 1, 20, 'Desired Effect, 1948 Oak Park Blvd, Pleasant Hill, CA, 94523', 'Jay Beecham', NULL, 'External', NULL, false, 'Streetwise Self Defense', 'Pleasant Hill', NULL, NULL, NULL, '2025-11-12 06:31:37+00', '2026-04-22 04:40:57.20177+00'),
	('fdde79e5-b349-4210-8d70-c82fcac3fad6', 'rec9TnQclhWQU22W3', 'Mothers&Daughters - Girl Scouts 7th Grade', 'Girl Scouts Self Defense -  7th Grade', NULL, 'Community: Mother & Daughter', '12-15', 3, 50, 'Mount Diablo Yoga Center, 2121 Ygnacio Valley Rd, Suite E207, Walnut Creek, CA 94598', 'Jay Beecham', 50, 'SWSD website', NULL, false, 'Streetwise Self Defense', 'Walnut Creek', 'THE EASIER APPROACH - From Ygnacio Valley Road, turn RIGHT (if coming from downtown Walnut Creek) or LEFT if traveling SW (Toward Walnut Creek) on Walnut Avenue.  The first entry into the office park on the left side of Walnut Avenue, goes directly toward Building E, and the stairs and ramp that are closest to suite 207 - See map.

If traveling East on Bancroft Road, approaching Ygnacio Valley Road, stay in the center lane, and cross Ygnacio Valley Road.  Turn Left into the first entry into the office park on Walnut Avenue, and follow that directly toward Building E, and the stairs and ramp that are closest to suite 207 - See map.

ALTERNATIVE APPROACH - to get to the front of Bldg. E, at 2121 Ygnacio Valley Road - Traveling NE, enter the driveway approximately 400 feet to the NE of the intersection between Ygnacio & Bancroft Rd./Walnut Ave., (after you pass Diablo Creek Dentistry, you will see a Red Brick Wall), you will see a driveway with the addresses 2021 - 2121 on the brick wall.  This driveway leads directly to 2121 Ygnacio Valley Road, Building E.  From there, you should work your way around the right side of the building until you see the stairs and access ramp at the back of the building.  Suite 207 is the first door on your right, just up the stairs.
', '/md-yoga-map.png', 'Per Person', '2025-11-18 23:46:49+00', '2026-04-22 04:40:57.20177+00'),
