	('4ee29a95-44e2-485b-af29-228d2baa27d8', 'recXFO30JwsC6jiQx', 50, 'Elise', 'Stafford', 'esumnicht@gmail.com', '5106150558', 'Private Training', NULL, 'New', false, NULL, NULL, 'I have a Girl Scout troop of 10 8th graders (13 and 14). I would like to know pricing for a class for them (and maybe some moms if you need a bigger group). I’d like to shoot for Nov/dec since that’s when it makes sense for indoor activities. ', 'Walnut Creek', 'California', NULL, NULL, '2025-08-23 19:17:06+00', '2026-04-22 04:40:58.649885+00'),
	('677b9a5c-267c-4c97-8bf5-b701b3c423ca', 'reca3nsVmWPv3lHe9', 54, 'Amy', 'Thomatis', 'amy@thomatis.com', '9254130222', 'Private Training', NULL, 'New', true, NULL, NULL, 'I''m interested in training for my kids.  My youngest is almost 18 and going off to college next year, and my other (transgender daughter) is 20.  They''ve both experienced creeps on the street and I want them to have a better skillset on how to deal with them.   ', 'TRACY', 'California', NULL, NULL, '2025-10-04 16:26:09+00', '2026-04-22 04:40:58.649885+00'),
	('88ac1b6e-e3b4-442f-8f40-cb18683a0996', 'recaMgdqkrE9BZGWq', 46, 'Test 7', 'Beecham', 'miriam.beecham@gmail.com', '2084846288', 'Private Training', NULL, 'New', false, NULL, NULL, 'asdfsadf', 'Test', 'California', NULL, NULL, '2025-08-20 18:14:02+00', '2026-04-22 04:40:58.649885+00'),
	('87ab37d4-5a6a-475b-aabc-b63b2dd8b902', 'recoMQ0s5Fq5oS67q', 53, 'Valerie', 'Liu', 'valerietliu@gmail.com', '3134859578', 'Private Training', NULL, 'New', false, NULL, NULL, 'I''m interested in setting up a self-defense small group class for a handful of moms and middle-school daughters and am curious about rates and availability for something like that. Thanks!', 'Fairfield ', 'California', NULL, NULL, '2025-09-18 21:36:35+00', '2026-04-22 04:40:58.649885+00'),
	('5db1bf49-079f-4e51-bde0-8c3747b2f0b1', 'recog9Lay5uyhdm1y', 48, 'M', 'B', 'm@gmail.com', '5552221212', 'Private Training', NULL, 'New', false, NULL, NULL, 'sdfasdf', 'w', 'California', NULL, NULL, '2025-08-20 19:25:03+00', '2026-04-22 04:40:58.649885+00'),
	('0bb9a2d8-9465-436a-bb47-961359f949a5', 'recslPday25xZoeOf', 55, 'Eileen', 'Bonifacio', 'eileenbonifacio@gmail.com', '4157945979', 'Private Training', NULL, 'New', false, NULL, NULL, 'To whom it may concern,

I hope this message finds you well. I am writing to inquire about the availability of private group self-defense classes at your facility.
I am interested in organizing a session for a group with participants of varying ages and would appreciate information on the following:

Whether you offer private co-ed group instruction for self-defense
Age requirements or accommodations for mixed-age groups
Available scheduling options and session duration
Pricing structure for group classes
Maximum and minimum group size requirements

If this is a service you provide, I would be grateful for any additional details about your program, including instructor qualifications and what participants should expect from the class.

Thank you for your time and consideration. I look forward to hearing from you at your earliest convenience.

Best,
Eileen', 'San Francisco', 'California', NULL, NULL, '2025-10-06 05:04:20+00', '2026-04-22 04:40:58.649885+00'),
	('d12783ed-5fcf-4c1b-ad2c-472c5af0792f', 'recsvHxWQN6XFVSuZ', 47, 'TEST10', 'BEECHAM', 'MIRIAM.BEECHAM@GMAIL.COM', '2084846288', 'Private Training', NULL, 'New', false, NULL, NULL, 'sadadf', 'test', 'California', NULL, NULL, '2025-08-20 18:21:09+00', '2026-04-22 04:40:58.649885+00'),
	('ba5aba74-a93c-415e-bbcb-de798589e7a3', 'reczuSrypCLUevfaf', 52, 'Christina', 'Taylor', 'ctaylor18@touro.edu', '707-638-5701', 'Workplace Safety', NULL, 'New', false, NULL, NULL, 'One of our students was assaulted and robbed in Vallejo and is feeling quite vulnerable and we are looking for a class that we can host on campus as well as a class in the area she could attend with classmates. ', 'Vallejo', 'California', 'Touro University California PA Program', 'Wellness Coordinator & Health Coach', '2025-09-15 18:29:25+00', '2026-04-22 04:40:58.649885+00');


