INSERT INTO "public"."testimonials" ("id", "airtable_record_id", "testimonial_id", "name", "content", "rating", "class_type", "platform", "review_date", "profile_picture", "platform_screenshot", "original_review_url", "profile_image_url", "is_featured", "is_published", "status", "internal_notes", "homepage_position", "created_at", "updated_at") VALUES
	('7b041f0d-78a9-4e08-9cc3-898e4d10dd82', 'rec3Xw1xj4Fy8GJ6y', NULL, 'Deborah Ryman, Board Member & Dir. of Operations, Gate of Hope', 'Attending Jay’s self-defense class with a group of teenage girls we mentor regularly was such a beautiful and empowering experience. Jay taught with great respect and knowledge and every one of the girls LOVED learning how to own their own space and stand up for their rights. I would highly recommend his class to anyone and we can’t wait to go again and learn more! Thank you so much Jay!
', NULL, NULL, 'survey', NULL, NULL, NULL, NULL, NULL, false, true, 'Active', NULL, 'cbo2', '2025-07-28 06:04:24+00', '2026-04-22 04:40:57.801128+00'),
	('c31904f4-63f6-4f45-b1b7-9492be91f512', 'rec62gkDrlPu0NAIe', NULL, 'Sarah W.', 'Jay really goes above and beyond to teach us how to feel safe in different situations. It was very female oriented and after the class I feel better able to defend myself
', '5', NULL, 'yelp', '2025-03-19', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/M4y7ChSdnY8YEunuiP8LYg/ls.jpg', false, true, 'Active', NULL, 'Quote 6', '2025-07-26 02:31:18+00', '2026-04-22 04:40:57.801128+00'),
	('ec01adcb-8f95-4b74-8e7b-8e84bc067d62', 'rec8thF0fRrhCKWXz', NULL, 'Samantha M.', 'Jay was amazing! Not only was the class informative, but it''s clear that Jay has a passion for what he does, which made the class that much more enjoyable.
It''s scary out there! If you are a woman, please take this class
', '5', NULL, 'yelp', '2025-02-19', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/w_nSjdbtlgPXbF7HYMJdnw/120s.jpg', false, true, 'Active', NULL, 'None', '2025-08-01 23:10:25+00', '2026-04-22 04:40:57.801128+00'),
	('bd3823ce-e313-4298-9233-55fe834461cb', 'rec9rUoPcdt1hg40n', NULL, 'Gina C.', 'Would highly recommend. I had a mom/daughter session and learned so much. Jay was excellent about explaining the self defense techniques.
', '5', NULL, 'yelp', '2025-03-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:17:10+00', '2026-04-22 04:40:57.801128+00'),
	('c5c92425-570f-429f-a8ba-a9743a5cbb3d', 'recB839HV4cdE735B', NULL, 'Chase M.', 'This was a very informative and useful class. Jay really went out of his way to show us various defensive measures and insisted we practice them with him many times until they became more natural for us. He obviously really cares about this issue and knows his stuff. Would highly recommend his course.
', '5', NULL, 'yelp', '2023-09-07', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/txL47dAKLB3MlikZrQf9Uw/120s.jpg', false, true, 'Active', NULL, 'None', '2025-08-01 23:21:06+00', '2026-04-22 04:40:57.801128+00'),
	('bbc75b1f-9dfc-400e-8d3f-9979602d5236', 'recro9mq5QvCHMX9i', NULL, 'Deirdre P.', 'Fantastic mother/daughter self defense course. Jay was absolutely the perfect coach to help make women of all ages feel like this is approachable and necessary. I was so impressed with how much information we gained in such a short amount of time. We will be taking this course a few times in the future to make sure the skills stick. Highly recommend!
', '5', NULL, 'yelp', '2025-07-07', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/H9rRlO5efLfoObFRsqpJyw/ls.jpg', false, true, 'Active', NULL, 'None', '2025-07-26 01:06:59+00', '2026-04-22 04:40:57.801128+00'),
	('8caaeb28-a57a-4417-9441-0b6e1391c77b', 'recBP2aYJQp3vvVas', NULL, 'Paula W.', 'Perhaps the most critical takeaway for me was the advantage of cultivating a fighting mindset. I learned that most of the moves work best when directly and swiftly manipulating the attacker - or parts of the attacker - which can mean a closer contact with someone we are wanting to flee. It can be just arms and fingers in some moves, but even with that it involves touching someone who scares us. It''s not what I might have thought instinctively to do but Jay takes us through those moves to show us how and why this is so effective.
The three hour workshop I attended provided me an overview and practice of several self defense moves which was exactly what I had hoped for. Jay went over a variety of encounters (from the front, from behind, from the side), and addressed questions and situations brought up by participants; all in a sensitive way.
', '5', NULL, 'yelp', '2024-02-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:20:01+00', '2026-04-22 04:40:57.801128+00'),
	('6d0b53a5-0165-41b7-a5a2-e104d2fafd67', 'recBp13eK8bW1C8Rg', NULL, 'Karin M.', 'I took Jay''s class at the Body Wisdom studio in Richmond. Jay is fantastic. He''s just the right guy for this class; he''s a kind, caring man who makes us feel safe from the start. He''s worked with survivors and has deep compassion for those who have suffered trauma. He lets us know from the start that we can sit out any exercise we want if it''s too triggering. He''s intuitive and respectful, checking in to make sure we''re feeling OK and asking permission before doing any touching. He teaches techniques for de-escalating and getting away to some amazing maneuvers for escaping an attack. Every teen and woman should take this class.
', '5', NULL, 'yelp', '2025-11-21', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/-Yu0oa_32eWcptjSE7uShA/ls.jpg', false, true, 'Active', NULL, 'None', '2026-03-01 03:02:20+00', '2026-04-22 04:40:57.801128+00'),
	('90c160dd-a7a0-4984-935e-c3d231e92e96', 'recFx4Jxdl6X3KvZS', NULL, 'Monica W.', 'I can''t say enough great things about Jay and his course. As a mom of a daughter who has special needs, I''ve been wanting to get her some training for quite some time but didn''t know where to turn. She wasn''t interested in studying martial arts. I didn''t want to wait years for her to learn some basic skills. Most importantly, I needed someone skilled enough and thoughtful enough to teach this sensitive material to a unique learner.

I ended up finding Streetwise Self-Defense online and after talking and texting multiple times with Jay, I knew I was in the right place. I organized a small class for my 20yo daughter and a couple of her friends. They are all neuro-diverse learners. Organizing the one-day class on such short notice took a little work, but Jay was super communicative and flexible. He went out of his way to make this work for us.

The girls went into class feeling a little unsure, but Jay quickly made them feel comfortable and empowered. Overall, they had a ton of fun; however, a couple of scenarios Jay walked them through did bring some discomfort. This is some heavy stuff, but situations they need to be aware of. I was impressed with the way Jay dealt with it calmly, matter-of-factly, and very professionally. He was tuned into and understanding of their emotional state when things got a little stressful and reminded them of their strength when they needed a little encouragement. Come the end of class, the girls felt incredibly energized and confident, and said they couldn''t wait to do it again.

Thanks for all you do, Jay. The girls are all looking forward to their next class with you.
', '5', NULL, 'yelp', '2025-03-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:19:16+00', '2026-04-22 04:40:57.801128+00'),
	('af5067c0-62a4-46f8-99c4-aaad1a25a411', 'recGzteQThXEbVBbX', NULL, 'Candice C.', 'Great class! Jay was kind, thorough and sensitive to everyone''s individual personal situations. The one on one practice is invaluable. I left with practical experience I feel like I could use! I will be back with my daughter.
', '5', NULL, 'yelp', '2025-11-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/SCy2TN0m18WBmJFaZcTLPg/ls.jpg', false, true, 'Active', NULL, 'None', '2026-03-01 03:03:43+00', '2026-04-22 04:40:57.801128+00'),
	('a59bf1ee-e061-4265-9eed-8970d72fcc0e', 'recH0aHrYOgoRCWGU', NULL, 'Beth A.', 'I enrolled myself and my 15 year old daughter in Jays'' Women''s self defense class at the Walnut Creek Civic community center. There were 7 females in my class and 3 of them were teenage girls and the others were moms and middle aged women like myself. This class was soo empowering and educational. It is soo much information that realistically one would need to take 1-3 additional classes after the first to be able to remember all the different maneuvers. However, it was a great stepping stone to being able to educate my daughter and have her and I talk about things we hadn''t really discussed up to this point. Jay has soo much knowledge and experience behind his techniques. It was a lot to fit into a three hour course. However, any longer of a class and we would have already maxed out on the information. He is very easy to talk to and he''s very kind and speaks in language that my daughter and I could both understand. I very much recommend this class to mothers and their daughters!
', '5', NULL, 'yelp', '2025-03-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:18:21+00', '2026-04-22 04:40:57.801128+00'),
	('c6bd6c51-d9e6-4a48-9ba8-d4a3a1bdd205', 'recHqio0jCG8162vK', NULL, 'Sarah W.', 'I took the Women''s Self Defense class with Jay at the Walnut Creek Arts and Rec Center. 10/10
Amazing! It was so informative and fun. 
', '5', NULL, 'yelp', '2025-03-19', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/M4y7ChSdnY8YEunuiP8LYg/ls.jpg', true, true, 'Active', NULL, 'None', '2025-07-26 20:22:56+00', '2026-04-22 04:40:57.801128+00'),
	('5a0583e6-b2a6-48cc-bc80-9b7ed3d8d28e', 'recIHrBJaWQvfiGhn', NULL, 'Alicia D.', 'I left this class EXCITED!!! I feel more able to be aware & avoid a variety of potentially BAD SITUATIONS. I did also trust Jay the instructors professional skill to “read the room” as to what we may need help with. I felt safe with him & the class to share that I had past traumas & my boundaries were kept & reassured & I accepted with warmth:)
I will be registering for more “STREETWISE SELF DEFENSE” classes ASAP!!
I would give SO MUCH to have this information when I needed it.
', '5', NULL, 'google', NULL, NULL, NULL, 'https://www.google.com/maps/contrib/115431869477226343145/reviews?hl=en', NULL, false, true, 'Active', NULL, 'None', '2025-07-26 02:48:12+00', '2026-04-22 04:40:57.801128+00'),
	('57528279-675a-45ef-99d4-e0a36dc5a49b', 'recNcX1UdaPvuzYqW', NULL, 'Sunday C.', 'Jay at Streetwise Self Defense is knowledgeable, dedicated, and respectful in his approach to empowering women through providing training in self-defense techniques. He offers a unique service in which he will provide training sessions on location upon request. I''m very satisfied with the quality of information shared, the pricing, and the overall outcome of the experience. I highly recommend his services to anyone seeking to educate themselves in self-defense. Thanks Jay at Streetwise Self Defense!
', '5', NULL, 'yelp', '2023-07-30', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:22:06+00', '2026-04-22 04:40:57.801128+00'),
	('88a27198-128a-4c07-b9f8-637f3eaa9a8f', 'recTZ1s9HCxrVza1n', NULL, 'Katee M.', 'Can''t recommend Jay and Streetwise Defense enough -- whether you''re looking to build confidence, learn how to protect yourself, or just want to do something meaningful with your group. This class was a game-changer!
', '5', NULL, 'yelp', '2025-07-21', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-07-26 01:08:10+00', '2026-04-22 04:40:57.801128+00'),
	('c06646c5-b29f-488b-9818-03c92076e0ee', 'recTvN2ravSSpwL7O', NULL, 'Theresa P.', 'Myself, my daughter and granddaughter recently completed the Streetwise Self Defense Class with Jay.  Jay is extremely knowledgable and has an extensive background in self defense.  Most importantly to me, my daughter and granddaughter was Jay''s ability to put us at ease and always remained respectful.  I highly recommend women of all ages to take Jay''s class.
', '5', NULL, 'google', '2025-08-12', NULL, NULL, 'https://www.google.com/maps/place/Streetwise+Self+Defense/@37.9132699,-122.0709112,16z/data=!4m8!3m7!1s0x808561767656b757:0xd2f8c4e44e94c78a!8m2!3d37.9132699!4d-122.0683363!9m1!1b1!16s%2Fg%2F11kj88gn7r?entry=ttu&g_ep=EgoyMDI1MDkxNy4wIKXMDSoASAFQAw%3D%3D', NULL, false, true, 'Active', NULL, 'None', '2025-09-19 19:51:28+00', '2026-04-22 04:40:57.801128+00'),
	('da8a9d42-d2fb-4bfb-afc3-3b4711ccc451', 'recUWiOqM8i2N6MNB', NULL, 'Rachel C.', 'The class was informative, professional, respectful and FUN! Jay made everyone feel comfortable right from the beginning. We bonded with the other women there and came away feeling confident and powerful
', NULL, NULL, 'survey', NULL, NULL, NULL, NULL, NULL, false, true, 'Active', NULL, 'Quote 2', '2025-07-26 02:45:43+00', '2026-04-22 04:40:57.801128+00'),
	('f2e3d792-0781-4fa0-8903-1e02147cfd48', 'recVRu270F3ng6X84', NULL, 'Alicia D.', 'I left this class EXCITED!!! I feel more able to be aware & avoid a variety of potentially BAD SITUATIONS...
I would give SO MUCH to have this information when I needed it.
', '5', NULL, 'google', NULL, NULL, NULL, 'https://www.google.com/maps/contrib/115431869477226343145/reviews?hl=en', NULL, false, true, 'Active', NULL, 'Quote 5', '2025-07-26 02:50:22+00', '2026-04-22 04:40:57.801128+00'),
	('57e584ae-7444-4ab1-8594-886723a88cc6', 'recXu7V7USIzK6F2M', NULL, 'Cassidy C.', '
This class was very empowering and made me feel much more confident. I know when and when not to use certain moves, and how to make it possible to get out of something bad. Jay is respectful and elegant with his work. I was impressed and intrigued by his skills.
', NULL, NULL, 'survey', NULL, NULL, NULL, NULL, NULL, false, true, 'Active', NULL, 'corporate2', '2025-07-28 06:26:36+00', '2026-04-22 04:40:57.801128+00'),
	('d5af6733-3226-4c3e-aaab-9538bbc6a811', 'recYSJ9IiyiLynIQj', NULL, 'Catherine H.', 'This is a truly wonderful and empowering class! I found Jay respectful, compassionate, and sensitive to the fear I brought with me. Jay hit all the right notes so that I not only felt safe emotionally, but began to learn some physical skills I want to remember. I highly recommend this experience!
', NULL, NULL, 'survey', '2022-07-01', NULL, NULL, NULL, NULL, false, true, 'Active', NULL, 'corporate1', '2025-07-28 06:05:54+00', '2026-04-22 04:40:57.801128+00'),
	('c10da35f-6533-4c8a-80fd-5dad29534e4b', 'recfIoaim6UMvD9CR', NULL, 'Angela V.', 'I took this class with my sister. Jay was a phenomenal teacher. He made sure we were comfortable while also pushing us outside our comfort zone as we learned how to protect ourselves. I appreciated the time we were given to practice the moves. Jay and the other instructors were so encouraging and celebrated with us when we figured out the moves. Jay also gave us wonderful safety tips. I plan on offering this class to my team if they are interested. I highly recommend this class to anyone who wants to learn how to protect themselves. Thank you Jay!!
', '5', NULL, 'yelp', '2025-11-23', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2026-03-01 03:05:58+00', '2026-04-22 04:40:57.801128+00'),
	('8c999d98-cbd6-4263-b082-159552d6765d', 'reckH9NVCJUWhWgMd', NULL, 'Deirdre P.', 'Fantastic mother/daughter self defense course. Jay was absolutely the perfect coach to help make women of all ages feel like this is approachable and necessary.
', NULL, NULL, 'yelp', '2025-07-07', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/H9rRlO5efLfoObFRsqpJyw/ls.jpg', false, true, 'Active', NULL, 'Quote 1', '2025-07-26 02:44:20+00', '2026-04-22 04:40:57.801128+00'),
	('26784e96-4246-43eb-801c-7f54cbc7b14b', 'recmjMLmbokIy4epl', NULL, 'Anna Delay, AVID Coordinator, Boise High School', 'Jay was incredibly kind, knowledgeable and easy to work with when he assisted my students in organizing a self-defense workshop for their fellow high school students. Jay met with the student-organizers ahead of the workshop so they could run through the moves themselves before assisting their peers in learning on the day of our workshop. The students and I found Jay and his assistant to be patient, funny and empowering to the (mostly) young women who were taking his course. After the workshop, participants felt stronger, more powerful and more confident that they can keep themselves safe and, in the event of an attack, they would be able to defend themselves. As a teacher, I’m so grateful to Jay for coming to Boise High School, for working with our young people and for offering his services to us. Thanks, Jay!
', NULL, NULL, 'survey', NULL, NULL, NULL, NULL, NULL, false, true, 'Active', NULL, 'cbo1', '2025-07-28 06:00:21+00', '2026-04-22 04:40:57.801128+00'),
	('8a663c07-c993-4f85-9a71-0d4f22937456', 'reco8Qi18tnwKDZ4S', NULL, 'Sarah W. ', 'I took the Women''s Self Defense class with Jay at the Walnut Creek Arts and Rec Center. 10/10
Amazing! It was so informative and fun. Jay really goes above and beyond to teach us how to feel safe in different situations. It was very female oriented and after the class I feel better able to defend myself. Jay has a ton of experience and really makes the subject of self defense approachable and easy to understand. I''m so grateful to have taken this class and I plan to repeat it in the future to keep up these skills! If you''re thinking about signing up do it!
', '5', NULL, 'yelp', '2023-07-30', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/M4y7ChSdnY8YEunuiP8LYg/ls.jpg', false, true, 'Active', NULL, 'None', '2025-08-04 19:36:07+00', '2026-04-22 04:40:57.801128+00'),
	('59759045-ff72-4baa-9946-ba893aa72088', 'recpNy9bDEWWtK4Xa', NULL, 'Natasha T.', 'The girls leaned some great defensive moves, strategies and gained confidence. Great investment.
', '5', NULL, 'yelp', '2023-08-09', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/VDwEiXK83GClTcRf6LgDpg/120s.jpg', false, true, 'Active', NULL, 'Quote 4', '2025-07-26 02:35:39+00', '2026-04-22 04:40:57.801128+00'),
	('4eaf456d-b3de-495f-819a-61cd57555eab', 'rectThd6yiJnNkYBk', NULL, 'T E.', 'My sister and I took Jay''s Streetwise Self Defense class together, and it was a blast! He taught us many self defense techniques, including how to escape a choke hold and how to kick an attacker. He helps every student realize the strength that they already have, which instantly boosts confidence and shifts one''s mindset about being able to approach different situations. He ensures all the moves are applicable and effective for all students, making adjustments accordingly. Jay is very passionate about teaching women how to protect themselves. He is well versed in common attacks women may face today and conducts practical drills to help students learn what they need to in real life scenarios. It was a very fun and informative session, and we recommend everyone take it!
', '5', NULL, 'yelp', '2026-02-21', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', 'https://s3-media0.fl.yelpcdn.com/photo/0VMX8_srrAbGn8ZI8vUBiA/ls.jpg', false, true, 'Active', NULL, 'None', '2026-03-01 02:58:10+00', '2026-04-22 04:40:57.801128+00'),
	('2666a4de-6d33-4630-b33a-8dd864852892', 'rectbIoFbGHXbKU9H', NULL, 'Katee M.', '...whether you''re looking to build confidence, learn how to protect yourself, or just want to do something meaningful with your group. This class was a game-changer!
', '5', NULL, 'yelp', '2025-07-21', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'Quote 3', '2025-07-26 02:38:56+00', '2026-04-22 04:40:57.801128+00'),
	('8aa3ca8a-d6e5-44c3-afe7-e9889eef1643', 'reczFrHP0sRd9xGEv', NULL, 'BayArea Consumer S.', 'Give the gift of confidence! An extremely empowering experience! I traveled from SF to Walnut Creek (2 hr. drive in traffic) with my daughter and two of her friends to attend Jay''s class. Absolutely worth the drive. My daughter and her friends will be headed off to college and I wanted them to have the skills needed to stay safe. Jay not only explains what to do in a scenario but also demonstrates how to get out of a situation and then you practice the technique on him. During the class, Jay met each person where they were. He is kind, compassionate and funny. The practicing part is the most important. My daughter and her friends left feeling more confident and as a parent I feel my daughter and her friends are better equipped to defend themselves if needed not only in college but in life. I wish I had learned these techniques 30 years ago... they would have come in handy!
', '5', NULL, 'yelp', '2025-08-01', NULL, NULL, 'https://www.yelp.com/biz/streetwise-self-defense-walnut-creek#reviews', NULL, false, true, 'Active', NULL, 'None', '2025-08-01 23:08:55+00', '2026-04-22 04:40:57.801128+00');


